I am using the below code to export to xlsx.

But it shows below warning in the excel cell for the quantity column       
![image](https://github.com/exceljs/exceljs/assets/8181185/cd6aaaec-0050-433b-856a-07509fd81681)


 const workbooka = new ExcelJS.Workbook();
const worksheeta = workbooka.addWorksheet('Sheet 1');

// Define your data with mixed data types
const data = [
  { item: 'Item 1', quantity: '10', price: 5 },
  { item: 'Item 2', quantity: 15, price: 8 },
  { item: 'Item 3', quantity: '12', price: 6 },
  // Add more data here
];

// Add headers to the worksheet
const headersa = Object.keys(data[0]);
worksheeta.addRow(headersa);

// Add data to the worksheet, explicitly setting the cell value to a string
data.forEach((item) => {
  const row = [];
  headersa.forEach((header) => {
    const value = item[header];
    row.push(value);
  });
  worksheeta.addRow(row);
});

// Generate a blob for the workbook and create a download link
workbooka.xlsx.writeBuffer().then((data) => {
  const blob = new Blob([data], {
    type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  });
  const url = window.URL.createObjectURL(blob);

  // Create a download link
  const a = document.createElement('a');
  a.href = url;
  a.download =  'mani.xlsx';
  document.body.appendChild(a);
  a.click();

  // Clean up
  window.URL.revokeObjectURL(url);
  document.body.removeChild(a);
});


